  1	import React, { useState } from 'react';
  2	import { useTempoResources } from '../../hooks/useTempoResources';
  3	import { QueryBrowser } from './QueryBrowser';
  4	import {
  5	  Button,
  6	  Divider,
  7	  Dropdown,
  8	  DropdownItem,
  9	  DropdownList,
 10	  EmptyState,
 11	  EmptyStateActions,
 12	  EmptyStateBody,
 13	  EmptyStateFooter,
 14	  EmptyStateHeader,
 15	  EmptyStateIcon,
 16	  MenuToggle,
 17	  Page,
 18	  PageSection,
 19	  Stack,
 20	  Title,
 21	} from '@patternfly/react-core';
 22	import { PlusCircleIcon, WrenchIcon, ExternalLinkAltIcon } from '@patternfly/react-icons';
 23	import { useTranslation } from 'react-i18next';
 24	import { useTempoInstance } from '../../hooks/useTempoInstance';
 25	import { ErrorAlert } from '../../components/ErrorAlert';
 26	import { LoadingState } from '../../components/LoadingState';
 27	import { Helmet, HelmetProvider } from 'react-helmet-async';
 28	import { Link } from 'react-router-dom-v5-compat';
 29	import { QueryParamProvider } from 'use-query-params';
 30	import { ReactRouterAdapter } from '../../react_router_adapter';
 31	
 32	const installOperatorLink =
 33	  '/operatorhub/all-namespaces?keyword=Tempo&details-item=tempo-product-redhat-operators-openshift-marketplace';
 34	const createTempoStackLink =
 35	  '/api-resource/all-namespaces/tempo.grafana.com~v1alpha1~TempoStack/instances';
 36	const createTempoMonolithicLink =
 37	  '/api-resource/all-namespaces/tempo.grafana.com~v1alpha1~TempoMonolithic/instances';
 38	const viewInstallationDocsLink =
 39	  'https://docs.redhat.com/en/documentation/openshift_container_platform/latest/html/distributed_tracing/distributed-tracing-platform-tempo';
 40	
 41	export default function TracesPage() {
 42	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
 43	
 44	  return (
 45	    <QueryParamProvider adapter={ReactRouterAdapter}>
 46	      <HelmetProvider>
 47	        <Helmet>
 48	          <title>{t('Tracing')}</title>
 49	        </Helmet>
 50	      </HelmetProvider>
 51	      <Page>
 52	        <TracesPageBody />
 53	      </Page>
 54	    </QueryParamProvider>
 55	  );
 56	}
 57	
 58	// TracesPageBody handles empty states like "Tempo Operator not installed" or "No Tempo instances created yet".
 59	function TracesPageBody() {
 60	  const { loading, error, tempoResources } = useTempoResources();
 61	  const [tempo] = useTempoInstance();
 62	
 63	  // show loading state (loading the list of Tempo CRs in the cluster)
 64	  // only if no Tempo instance is selected (from the query params)
 65	  if (!tempo && loading) {
 66	    return <LoadingState />;
 67	  }
 68	
 69	  if (error) {
 70	    if (error.errorType === 'TempoCRDNotFound') {
 71	      return <TempoOperatorNotInstalledState />;
 72	    } else {
 73	      return <ErrorState errorType={error.errorType} error={error.error} />;
 74	    }
 75	  }
 76	
 77	  if (!loading && tempoResources && tempoResources.length === 0) {
 78	    return <NoTempoInstance />;
 79	  }
 80	
 81	  return <QueryBrowser />;
 82	}
 83	
 84	function TempoOperatorNotInstalledState() {
 85	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
 86	  return (
 87	    <>
 88	      <PageSection variant="light">
 89	        <Title headingLevel="h1">{t('Traces')}</Title>
 90	      </PageSection>
 91	      <PageSection>
 92	        <EmptyState>
 93	          <EmptyStateHeader
 94	            titleText={t("Tempo operator isn't installed yet")}
 95	            headingLevel="h4"
 96	            icon={<EmptyStateIcon icon={WrenchIcon} />}
 97	          />
 98	          <EmptyStateBody>
 99	            {t(
100	              'To get started, install the Tempo operator and create a TempoStack or TempoMonolithic instance with multi-tenancy enabled.',
101	            )}
102	          </EmptyStateBody>
103	          <EmptyStateFooter>
104	            <EmptyStateActions>
105	              <Button component={(props) => <Link {...props} to={installOperatorLink} />}>
106	                {t('Install Tempo operator')}
107	              </Button>
108	            </EmptyStateActions>
109	          </EmptyStateFooter>
110	        </EmptyState>
111	      </PageSection>
112	    </>
113	  );
114	}
115	
116	function NoTempoInstance() {
117	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
118	  const [isOpen, setOpen] = useState(false);
119	
120	  return (
121	    <>
122	      <PageSection variant="light">
123	        <Title headingLevel="h1">{t('Traces')}</Title>
124	      </PageSection>
125	      <PageSection>
126	        <EmptyState>
127	          <EmptyStateHeader
128	            titleText={t('No Tempo instances yet')}
129	            headingLevel="h4"
130	            icon={<EmptyStateIcon icon={PlusCircleIcon} />}
131	          />
132	          <EmptyStateBody>
133	            {t(
134	              'To get started, create a TempoStack or TempoMonolithic instance with multi-tenancy enabled.',
135	            )}
136	          </EmptyStateBody>
137	          <EmptyStateFooter>
138	            <EmptyStateActions>
139	              <Dropdown
140	                isOpen={isOpen}
141	                onOpenChange={setOpen}
142	                toggle={(toggleRef) => (
143	                  <MenuToggle
144	                    ref={toggleRef}
145	                    variant="primary"
146	                    onClick={() => setOpen(!isOpen)}
147	                    isExpanded={isOpen}
148	                  >
149	                    {t('Create a Tempo instance')}
150	                  </MenuToggle>
151	                )}
152	              >
153	                <DropdownList>
154	                  <DropdownItem key="createTempoStackLink" to={createTempoStackLink}>
155	                    {t('Create a TempoStack instance')}
156	                  </DropdownItem>
157	                  <DropdownItem key="createTempoMonolithicLink" to={createTempoMonolithicLink}>
158	                    {t('Create a TempoMonolithic instance')}
159	                  </DropdownItem>
160	                </DropdownList>
161	              </Dropdown>
162	            </EmptyStateActions>
163	            <EmptyStateActions>
164	              <Button
165	                variant="link"
166	                component="a"
167	                href={viewInstallationDocsLink}
168	                icon={<ExternalLinkAltIcon />}
169	                iconPosition="right"
170	              >
171	                {t('View documentation')}
172	              </Button>
173	            </EmptyStateActions>
174	          </EmptyStateFooter>
175	        </EmptyState>
176	      </PageSection>
177	    </>
178	  );
179	}
180	
181	interface ErrorStateProps {
182	  errorType?: string;
183	  error: string;
184	}
185	
186	function ErrorState({ errorType, error }: ErrorStateProps) {
187	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
188	  return (
189	    <PageSection variant="light">
190	      <Stack hasGutter>
191	        <Title headingLevel="h1">{t('Tracing')}</Title>
192	        <Divider />
193	        <ErrorAlert error={{ name: errorType ?? t('Error'), message: error }} />
194	      </Stack>
195	    </PageSection>
196	  );
197	}

